## 2.  C / C++ stub – **`pcapng_stubs.c`**

```c
/* pcapng_stubs.c – C/C++ glue for the OCaml binding.
 *
 * This file is deliberately self‑contained: it contains a tiny mock‑up
 * of the libpcapng C++ API (replace the mock with the real header), the
 * OCaml custom block definition that owns the C++ object, and the three
 * primitives declared in the .mli.
 *
 * Build with:
 *   ocamlc -c -I $(OCAML_INC) pcapng_stubs.c
 *   ocamlopt -output-obj -o pcapng_stubs.o pcapng_stubs.c
 *   ocamlopt -o my_program.exe pcapng.cmo pcapng_stubs.o -cclib -lpcapng
 *
 * (or the equivalent dune stanza – see the comment at the end of the file).
 */

#define CAML_NAME_SPACE               /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/callback.h>
#include <caml/signals.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

/* ------------------------------------------------------------------ */
/* 1.  Minimal mock‑up of the libpcapng C++ API.
 *     Replace this with the real header / library.                     */
#ifdef __cplusplus
extern "C" {
#endif

/* A frame returned by the iterator. */
struct Frame {
    double          timestamp;   /* seconds since epoch */
    std::vector<unsigned char> data;   /* payload */
};

/* The iterator class – the real library will have a richer API. */
class PcapNgReader {
public:
    explicit PcapNgReader(const std::string& filename) : idx_(0) {
        /* In a real implementation you would open the file here,
           parse the Section Header Block, etc.  For the mock we just
           pretend there are three static frames. */
        if (filename.empty())
            throw std::runtime_error("empty filename");
        frames_.push_back({ 1620000000.0, {0x45,0x00,0x00,0x54} });
        frames_.push_back({ 1620000000.1, {0x08,0x00,0x27,0x13,0x69,0x77} });
        frames_.push_back({ 1620000000.2, {0x60,0x00,0x00,0x00} });
    }

    /* Return true while there are more frames; false when EOF. */
    bool next(Frame& out) {
        if (idx_ >= frames_.size()) return false;
        out = frames_[idx_++];
        return true;
    }

    /* Explicit close (also called from the OCaml finalizer). */
    void close() { /* no‑op for the mock */ }

private:
    size_t idx_;
    std::vector<Frame> frames_;
};

#ifdef __cplusplus
}
#endif
/* ------------------------------------------------------------------ */

/* 2.  OCaml custom block that holds a PcapNgReader*.
 *
 * The custom block is a pointer to the C++ object.  The finalizer
 * releases the object when the OCaml value becomes unreachable.
 */
static void pcapng_finalize(value v) {
    PcapNgReader **p = (PcapNgReader **)Data_custom_val(v);
    if (p && *p) {
        (*p)->close();
        delete *p;
        *p = NULL;
    }
}

/* No special comparison / hashing needed – use the defaults. */
static struct custom_operations pcapng_ops = {
    "pcapng_reader_custom_ops",
    pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default
};

/* Allocate a custom block from a freshly‑created reader. */
static value alloc_pcapng_reader(PcapNgReader *r) {
    value v = caml_alloc_custom(&pcapng_ops, sizeof(PcapNgReader *), 0, 1);
    PcapNgReader **p = (PcapNgReader **)Data_custom_val(v);
    *p = r;
    return v;
}

/* ------------------------------------------------------------------ */
/* 3.  Primitive: open_file : string -> t */
CAMLprim value caml_pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_res);
    const char *c_path = String_val(v_path);
    try {
        PcapNgReader *r = new PcapNgReader(std::string(c_path));
        v_res = alloc_pcapng_reader(r);
    } catch (const std::exception& ex) {
        caml_failwith(ex.what());
    }
    CAMLreturn(v_res);
}

/* ------------------------------------------------------------------ */
/* 4.  Primitive: close : t -> unit */
CAMLprim value caml_pcapng_close(value v_reader) {
    CAMLparam1(v_reader);
    /* The finalizer already does the right thing; we just invoke it
       explicitly so the user can close early. */
    pcapng_finalize(v_reader);
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------ */
/* 5.  Primitive: iter_frames : t -> (frame -> unit) -> unit
 *
 * This walks the native iterator and, for each frame, builds an OCaml
 * record of type:
 *
 *   type frame = { ts : float; data : bytes }
 *
 * and calls the supplied OCaml closure.  If the closure raises, we
 * abort the iteration and re‑raise the exception.
 */
CAMLprim value caml_pcapng_iter_frames(value v_reader, value v_cb) {
    CAMLparam2(v_reader, v_cb);
    CAMLlocal3(v_frame, v_ts, v_data);
    /* Extract the native reader */
    PcapNgReader *r = *((PcapNgReader **)Data_custom_val(v_reader));
    if (r == NULL) caml_failwith("PcapNgReader is already closed");

    /* Prepare for long‑running C code – release the OCaml runtime lock. */
    caml_release_runtime_system();

    Frame native_frame;
    while (r->next(native_frame)) {
        /* Re‑acquire the lock before calling back into OCaml. */
        caml_acquire_runtime_system();

        /* Build the OCaml record { ts; data } */
        v_ts   = caml_copy_double(native_frame.timestamp);
        v_data = caml_alloc_initialized_string(
                     native_frame.data.size(),
                     reinterpret_cast<const char*>(native_frame.data.data())
                 );

        v_frame = caml_alloc(2, 0);          /* two‑field record, tag 0 */
        Store_field(v_frame, 0, v_ts);
        Store_field(v_frame, 1, v_data);

        /* Call the user’s callback.  Use callback_exn so we can detect
           exceptions without crashing the C++ side. */
        value v_res = caml_callback_exn(v_cb, v_frame);
        if (Is_exception_result(v_res)) {
            /* Propagate the exception back to OCaml.  The runtime lock
               is already held at this point, so caml_raise works. */
            caml_raise(v_res);
        }

        /* Release the lock again before the next native iteration. */
        caml_release_runtime_system();
    }

    /* Ensure the lock is held when we return to OCaml. */
    caml_acquire_runtime_system();
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------ */
/* 6.  Register the primitives for the OCaml side.
 *
 * The names used here must match the identifiers declared in the .mli.
 */
static struct caml_named_value caml_named_values[] = {
    CAML_DEF("pcapng_open_file", caml_pcapng_open_file),
    CAML_DEF("pcapng_close",      caml_pcapng_close),
    CAML_DEF("pcapng_iter_frames", caml_pcapng_iter_frames),
    { NULL, NULL }
};

/* The Dune (or ocamlbuild) build system automatically registers the
 * primitives when the object file is linked.  If you compile manually,
 * add the following line in your `main.c` (or any file linked with the
 * runtime):
 *
 *   caml_register_named_values(caml_named_values);
 *
 * Dune example:
 *
 * (library
 *  (name pcapng)
 *  (foreign_stubs
 *   (language c)
 *   (names pcapng_stubs))
 *  (libraries ctypes))   (* optional, only if you also expose a Ctypes API *)
 *
 * The .mli file should be placed in the same directory as the .c file,
 * and the generated .cmi/.cmo/.cmx will be the public OCaml API.
 */

/* End of pcapng_stubs.c */```

